    29	  Future<AthleteProfile> _loadProfile() =>
    30	      PrefsRepository.create().then((r) => r.loadAthleteProfile());
    31	
    32	  @override
    33	  Widget build(BuildContext context) {
    34	    return StreamBuilder<User?>(
    35	      stream: FirebaseAuth.instance.authStateChanges(),
    36	      builder: (context, snapshot) {
    37	        if (snapshot.connectionState == ConnectionState.waiting) {
    38	          return const Scaffold(
    39	            key: AuthGateKeys.loadingScreenKey,
    40	            body: Center(child: CircularProgressIndicator()),
    41	          );
    42	        }
    43	
    44	        if (snapshot.data == null) {
    45	          _profileFuture = null;
    46	          _lastUid = null;
    47	          return const AuthScreen(key: AuthGateKeys.authScreenKey);
    48	        }
    49	
    50	        final uid = snapshot.data!.uid;
    51	        if (_profileFuture == null || _lastUid != uid) {
    52	          _profileFuture = _loadProfile();
    53	          _lastUid = uid;
    54	        }
    55	
    56	        return FutureBuilder<AthleteProfile>(
    57	          future: _profileFuture,
    58	          builder: (context, roleSnapshot) {
    59	            if (!roleSnapshot.hasData) {
    60	              return const Scaffold(
    61	                key: AuthGateKeys.loadingScreenKey,
    62	                body: Center(child: CircularProgressIndicator()),
    63	              );
    64	            }
    65	            final profile = roleSnapshot.data!;
    66	            if (profile.role.isEmpty) {
    67	              return RoleSetupScreen(
    68	                key: AuthGateKeys.authScreenKey,
    69	                onSaved: () =>
    70	                    setState(() => _profileFuture = _loadProfile()),
    71	              );
    72	            }
    73	            return const StartupSyncedClickerScreen(
    74	              key: AuthGateKeys.startupSyncScreenKey,
    75	            );
    76	          },
    77	        );
    78	      },
    79	    );
