410	  AppLocalizations l10n,
411	  ShakeSensitivity sensitivity,
412	) {
413	  switch (sensitivity) {
414	    case ShakeSensitivity.low:
415	      return l10n.shakeSensitivityLow;
416	    case ShakeSensitivity.medium:
417	      return l10n.shakeSensitivityMedium;
418	    case ShakeSensitivity.high:
