423	int? parseStrictInt(String value, {required int min}) {
424	  final parsed = int.tryParse(value.trim());
425	  if (parsed == null || parsed < min) return null;
426	  return parsed;
427	}
428	
429	Duration? parseStrictDuration(String days, String hours, String minutes) {
430	  final parsedDays = parseStrictInt(days, min: 0);
431	  final parsedHours = parseStrictInt(hours, min: 0);
432	  final parsedMinutes = parseStrictInt(minutes, min: 0);
433	  if (parsedDays == null || parsedHours == null || parsedMinutes == null) {
434	    return null;
435	  }
436	  if (parsedHours >= 24 || parsedMinutes >= 60) {
437	    return null;
438	  }
439	
440	  final duration = Duration(
441	    days: parsedDays,
442	    hours: parsedHours,
443	    minutes: parsedMinutes,
444	  );
445	  return duration.inSeconds > 0 ? duration : null;
446	}

